/**
 * Type guard for SimulationResult validation
 */
export function isValidSimulationResult(obj: unknown): obj is SimulationResult {
  if (typeof obj !== 'object' || obj === null) return false;
  const result = obj as Record<string, unknown>;
  return (
    typeof result.poblacion_futura === 'number' &&
    typeof result.expectativa_vida_optimizada === 'number' &&
    typeof result.optimization_time_ms === 'number' &&
    typeof result.algorithm_used === 'string'
  );
}

/**
 * Type guard for PowerGridMetrics validation
 */
export function isValidPowerGridMetrics(obj: unknown): obj is PowerGridMetrics {
  if (typeof obj !== 'object' || obj === null) return false;
  const result = obj as Record<string, unknown>;
  return (
    typeof result.total_power_mw === 'number' &&
    typeof result.grid_efficiency === 'number' &&
    typeof result.quantum_optimized === 'boolean'
  );
}

/**
 * Type guard for Cuarzo4DState validation
 */
export function isValidCuarzo4DState(obj: unknown): obj is Cuarzo4DState {
  if (typeof obj !== 'object' || obj === null) return false;
  const result = obj as Record<string, unknown>;
  return (
    Array.isArray(result.dimensions) &&
    result.dimensions.length === 4 &&
    typeof result.data_points === 'number' &&
    typeof result.resolution_scale === 'number'
  );
}

