import { useEffect, useState, useCallback } from 'react';

/**
 * React Hook: useQuantumEnergyOS
 * Provides optimized quantum kernel instance with lifecycle management
 */
export function useQuantumEnergyOS(
  configPath?: string,
  enablePhotonicBridge?: boolean
): {
  quantumOS: QuantumEnergyOS | null;
  loading: boolean;
  error: Error | null;
  initialize: () => Promise<void>;
  shutdown: () => Promise<void>;
} {
  const [quantumOS, setQuantumOS] = useState<QuantumEnergyOS | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const initialize = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const instance = await createQuantumEnergyOS(configPath, enablePhotonicBridge);
      setQuantumOS(instance);
    } catch (err) {
      setError(err instanceof Error ? err : new Error(String(err)));
    } finally {
      setLoading(false);
    }
  }, [configPath, enablePhotonicBridge]);

  const shutdown = useCallback(async () => {
    if (quantumOS) {
      await quantumOS.shutdown();
      setQuantumOS(null);
    }
  }, [quantumOS]);

  // Auto-initialize on mount
  useEffect(() => {
    initialize();
    return () => {
      shutdown();
    };
  }, []);

  return { quantumOS, loading, error, initialize, shutdown };
}

/**
 * React Hook: useCuarzo4DVisualization
 * Manages Cuarzo 4D holographic visualization state
 */
export function useCuarzo4DVisualization(
  quantumOS: QuantumEnergyOS | null
): {
  cuarzoState: Cuarzo4DState | null;
  updateDimensions: (dims: [number, number, number, number], scale: number) => Promise<void>;
} {
  const [cuarzoState, setCuarzoState] = useState<Cuarzo4DState | null>(null);

  const updateDimensions = useCallback(async (dims: [number, number, number, number], scale: number) => {
    if (quantumOS) {
      await quantumOS.updateCuarzoDimensions(dims, scale);
      const newState = await quantumOS.getCuarzo4DState();
      setCuarzoState(newState);
    }
  }, [quantumOS]);

  // Poll for state updates (every 100ms for real-time vis)
  useEffect(() => {
    if (!quantumOS) return;

    const interval = setInterval(async () => {
      const state = await quantumOS.getCuarzo4DState();
      setCuarzoState(state);
    }, 100);

    return () => clearInterval(interval);
  }, [quantumOS]);

  return { cuarzoState, updateDimensions };
}

